import openpyxlimport pathlib"""Домашняя библиотека"""class BookError(Exception):    """Raised when there is problem with creating book"""    class LibraryError(Exception):    """Raised when there is problem with library"""    class Book:    """Репрезентация книи в библиотеке"""    GENRES = ["фантастика", "ужасы", "драма", "фэнтези", "любовное", "эротическое"]    FORMS = ["роман", "повесть", "рассказ", "антология", "стих", "статья"]    def __init__(self, title, author, form="", genre="", rating=0, year=0, review=""):        Book.CheckingRating(rating)        Book.CheckingGenre(genre)        self.title = title        self.author = author        self.form = form        self.genre = genre        self.rating = rating        self.year = year        self.review = review    def __repr__(self):        return (f"Title - {self.title}, author - {self.author}, form - {self.form}, "         f"genre - {self.genre}, rating - {self.rating}, year - {self.year}")    def __str__(self):        return (f"{self.title}, за авторством {self.author}. {self.genre}, {self.form}. "         f" Оценка - {self.rating}. Год - {self.year if self.year != 0 else 'не указан'}\n"        f"отзыв - {self.review}")    def title_uptate(self, title):        self.title = title    def author_update(self, author):        self.author = author    def form_update(self, form):        self.form = form    def ganre_update(self, genre):        Book.CheckingGenre(genre)        self.genre = genre    def rating_update(self, rating):        Book.CheckingRating(rating)        self.rating = rating    def year_update(self, year):        self.year = year    def CheckingRating(rating):        if not isinstance(rating, (int, float)) or (rating>10 or rating<0):            raise BookError("Rating must be number range from 0 to 10")    def CheckingGenre(genre):        if isinstance(genre, list):            for elem in genre:                if elem.strip(" ") not in Book.GENRES:                    raise BookError("Unknown form")        else:            if genre not in Book.GENRES:                raise BookError("Unknown form")          class Library: #TODO добавить для нескольких жанров и авторов; добавить топ книг    lib_path = pathlib.Path.home() / "Desktop/home_library"    num_of_info = 7    EXCLUSIVE = False    def __init__(self, name):        self.name = name        pathlib.Path(Library.lib_path).mkdir(exist_ok=True)        if (Library.lib_path / f"{name}.xlsx").is_file():            pass        else:            library = openpyxl.Workbook()            types = ["title", "author", "form", "genre", "rating", "year", "review"]            ws = library.active            for i in range (1, Library.num_of_info+1):                ws.cell(1, i).value = types[i-1]            library.save(Library.lib_path / f"{self.name}.xlsx")    def book_add(self, book):        wb, ws = self.openlibrary()        for i in range(1, ws.max_row+1):            if book.title == ws.cell(i, 1).value:                book_title = book.title                book_author = ws.cell(i, 2).value                book_elements = [ws.cell(i, k).value for k in range(3, Library.num_of_info+1)]                book_args = [ws.cell(1, k).value for k in range(3, Library.num_of_info+1)]                other = dict(zip(book_args, book_elements))                BookDupli = Library.create_book_obj(book_title, book_author, **other)                raise LibraryError(f"Книга с таким названием уже есть в библиотеке: {str(BookDupli)}")        book_row = ws.max_row+1        for i in range(1, Library.num_of_info+1):            ws.cell(book_row, i).value = list(vars(book).values())[i-1]        wb.save(Library.lib_path / f"{self.name}.xlsx")    def filter_books(self, exclusive=False, **kwargs): # Словарь, где key - принуип поиска, value - то, что ищем        wb, ws = self.openlibrary()        elements_of_search = list(kwargs.keys())        values_to_search = list(kwargs.values())        rows_needed = []        books = []        for i in range(1, Library.num_of_info+1):            if ws.cell(1, i).value in elements_of_search:                rows_needed.append(i)        for i in range (1, ws.max_row+1):            summa = 0            counter = 0            for elem in rows_needed:                if ws.cell(i, elem).value == values_to_search[counter]:                    summa += 1                counter += 1            if summa == len(elements_of_search):                book_title = ws.cell(i, 1).value                book_author = ws.cell(i, 2).value                book_elements = [ws.cell(i, k).value for k in range(3, Library.num_of_info+1)]                book_args = [ws.cell(1, k).value for k in range(3, Library.num_of_info+1)]                other = dict(zip(book_args, book_elements))                BookFetched = Library.create_book_obj(book_title, book_author, **other)                books.append(BookFetched)        if len(books) == 0:            print("Не удалось найти книги, удовлетворяющие запросу")        else:            print("Вот книги, удовлетворяющие запросу:")            for book in books:                print(book)        wb.save(Library.lib_path / f"{self.name}.xlsx")    def delete_book(self, **kwargs): #словарь где ключи - title, значения - author        wb, ws = self.openlibrary()        titles = list(kwargs.keys())        authors = list(kwargs.values())        indexes = []        for cur_title in range(len(titles)):            for i in range(1, ws.max_row+1):                if ws.cell(i, 1).value == titles[cur_title] and ws.cell(i, 2).value == authors[cur_title]:                    indexes.append(i)        for row in indexes[::-1]:            ws.delete_rows(row)        wb.save(Library.lib_path / f"{self.name}.xlsx")    def openlibrary(self):        wb = openpyxl.load_workbook(Library.lib_path / f"{self.name}.xlsx")        ws = wb.active        return wb, ws    def create_book_obj(title, author, **kwargs):        return Book(title, author, **kwargs)            Book1 = Book("Ужасные ужасы", "Иванов", "рассказ", "ужасы", 10)Book2 = Book("Фантастическая фантастика", "Орлов", "",  "фантастика", 8, 2004)Book3 = Book("Любовная любовь", "Кириешков", "повесть", "любовное", 10, 2007)Book4 = Book("Новые ужасы", "Варварова", "антология", "ужасы", 10)Book5 = Book("Новейшие ужасы", "Варварова", "антология", "ужасы", 8, review = "Невероятно")test_books = (Book1, Book2, Book3, Book4, Book5)lib1 = Library("Lib")#for book in test_books:    #lib1.book_add(book)    